const llmOutput =
  items[0].json?.content?.parts?.[0]?.text ??
  items[0].json?.message ??
  items[0].json?.text ??
  items[0].json;

let parsed;

try {
  // Try to parse the LLM output
  if (typeof llmOutput === 'string') {
    parsed = JSON.parse(llmOutput);
  } else {
    parsed = llmOutput;
  }
} catch (e) {
  throw new Error('invalid_llm_json: Failed to parse JSON - ' + e.message);
}

// Validate structure
if (!parsed.questions || !Array.isArray(parsed.questions)) {
  throw new Error('invalid_llm_json: Missing or invalid questions array');
}

const questionCount = $('Normalize Defaults and Trim Text').item.json.question_count;
if (parsed.questions.length !== questionCount) {
  throw new Error(`invalid_llm_json: Expected ${questionCount} questions, got ${parsed.questions.length}`);
}

const questionType = $('Normalize Defaults and Trim Text').item.json.question_type;

// Validate each question based on type
for (let i = 0; i < parsed.questions.length; i++) {
  const q = parsed.questions[i];

  if (questionType === 'mcq') {
    // Validate MCQ questions
    if (!q.prompt || q.prompt.trim() === '') {
      throw new Error(`invalid_llm_json: Question ${i + 1} has empty prompt`);
    }

    if (!Array.isArray(q.choices) || q.choices.length !== 4) {
      throw new Error(`invalid_llm_json: Question ${i + 1} must have exactly 4 choices`);
    }

    if (!q.correct_choice || !q.choices.includes(q.correct_choice)) {
      throw new Error(`invalid_llm_json: Question ${i + 1} correct_choice must match one of the choices`);
    }
  } else if (questionType === 'tf') {
    // Validate True/False questions
    if (!q.question || q.question.trim() === '') {
      throw new Error(`invalid_llm_json: Question ${i + 1} has empty question`);
    }

    if (typeof q.answer !== 'boolean') {
      throw new Error(`invalid_llm_json: Question ${i + 1} answer must be true or false`);
    }

    if (!q.explanation || q.explanation.trim() === '') {
      throw new Error(`invalid_llm_json: Question ${i + 1} has empty explanation`);
    }
  } else if (questionType === 'fill') {
    // Validate Fill-in-Blank questions
    if (!q.question || q.question.trim() === '') {
      throw new Error(`invalid_llm_json: Question ${i + 1} has empty question`);
    }

    if (!q.question.includes('______')) {
      throw new Error(`invalid_llm_json: Question ${i + 1} must contain a blank (______)`);
    }

    if (!Array.isArray(q.correct_answers) || q.correct_answers.length < 2 || q.correct_answers.length > 5) {
      throw new Error(`invalid_llm_json: Question ${i + 1} must have 2-5 correct_answers`);
    }

    if (!Array.isArray(q.required_keywords) || q.required_keywords.length < 1 || q.required_keywords.length > 3) {
      throw new Error(`invalid_llm_json: Question ${i + 1} must have 1-3 required_keywords`);
    }

    if (!q.explanation || q.explanation.trim() === '') {
      throw new Error(`invalid_llm_json: Question ${i + 1} has empty explanation`);
    }
  } else {
    throw new Error(`invalid_llm_json: Unknown question type: ${questionType}`);
  }
}

// Return validated data with normalized fields
return [{
  json: {
    subject: parsed.subject || $('Normalize Defaults and Trim Text').item.json.subject,
    topic: parsed.topic || $('Normalize Defaults and Trim Text').item.json.topic,
    questions: parsed.questions,
    upload_id: $('Normalize Defaults and Trim Text').item.json.upload_id,
    user_id: $('Normalize Defaults and Trim Text').item.json.user_id,
    difficulty: $('Normalize Defaults and Trim Text').item.json.difficulty,
    question_count: questionCount,
    question_type: questionType
  }
}];

