={{
  const questions = $('Parse and Validate LLM JSON').item.json.questions || [];
  const quizId = $('POST Quiz to Supabase').item.json.id || $('POST Quiz to Supabase').item.json[0]?.id;

  return questions.map(q => {
    // Handle MCQ type
    if (q.type === 'mcq') {
      const idx = (q.choices || []).indexOf(q.correct_choice);
      const label = idx >= 0 ? ['A','B','C','D'][idx] : null;
      return {
        quiz_id: quizId,
        type: 'mcq',
        prompt: (q.prompt || '').trim(),
        choices: q.choices,
        answer_hash: label?.toLowerCase(),
        correct_label: label,
        hint: q.explanation ?? q.hint ?? null
      };
    }

    // Handle True/False type
    if (q.type === 'tf') {
      return {
        quiz_id: quizId,
        type: 'tf',
        prompt: (q.question || q.prompt || '').trim(),
        choices: ['True', 'False'],
        answer_hash: q.answer === true ? 'true' : 'false',
        correct_label: q.answer === true ? 'True' : 'False',
        hint: q.explanation ?? q.hint ?? null
      };
    }

    // Handle Fill-in-the-Blank type
    if (q.type === 'fill') {
      return {
        quiz_id: quizId,
        type: 'fill',
        prompt: (q.question || q.prompt || '').trim(),
        choices: null,
        answer_hash: JSON.stringify({
          correct_answers: q.correct_answers || [],
          required_keywords: q.required_keywords || []
        }),
        correct_label: (q.correct_answers || [])[0] || null,
        hint: q.explanation ?? q.hint ?? null
      };
    }

    // Fallback for unknown types
    return {
      quiz_id: quizId,
      type: q.type || 'mcq',
      prompt: (q.prompt || q.question || '').trim(),
      choices: q.choices || null,
      answer_hash: null,
      correct_label: null,
      hint: q.explanation ?? q.hint ?? null
    };
  });
}}
